function solve(s) {
    // Step 1: Calculate Frequencies
    const freqMap = new Map();
    for (const char of s) {
        freqMap.set(char, (freqMap.get(char) || 0) + 1);
    }

    /**
     * Determines the mirror character for a given input character.
     * @param {string} char 
     * @returns {string} The mirror character.
     */
    function getMirror(char) {
        const code = char.charCodeAt(0);

        // Check if it's a lowercase letter ('a' to 'z')
        if (code >= 97 && code <= 122) {
            // 'a' (97) maps to 'z' (122). Distance from 'a' is (code - 97).
            // Mirror index from 'z' end is 25 - (code - 97).
            // Mirror ASCII = 97 + (25 - (code - 97))
            const index = code - 97;
            const mirrorIndex = 25 - index;
            return String.fromCharCode(97 + mirrorIndex);
        } 
        // Check if it's a digit ('0' to '9')
        else if (code >= 48 && code <= 57) {
            // '0' (48) maps to '9' (57).
            // Distance from '0' is (code - 48).
            // Mirror index from '9' end is 9 - (code - 48).
            // Mirror ASCII = 48 + (9 - (code - 48))
            const index = code - 48;
            const mirrorIndex = 9 - index;
            return String.fromCharCode(48 + mirrorIndex);
        }
        // Should not happen based on problem constraints
        return char; 
    }

    let totalDifference = 0;
    const processedPairs = new Set();

    // Step 2 & 3: Iterate through unique characters in s and calculate differences
    for (const c of freqMap.keys()) {
        const m = getMirror(c);

        // Determine the canonical representation of the pair {c, m}
        // Use lexicographical comparison to ensure (c, m) and (m, c) are treated as one.
        const p1 = c < m ? c : m;
        const p2 = c < m ? m : c;
        const pairKey = p1 + p2;

        if (!processedPairs.has(pairKey)) {
            processedPairs.add(pairKey);

            const freqC = freqMap.get(c);
            // Get frequency of mirror character m, defaulting to 0 if m is not in s
            const freqM = freqMap.get(m) || 0;

            // Calculate absolute difference and add to total
            totalDifference += Math.abs(freqC - freqM);
        }
    }

    return totalDifference;
}

